Here's a dummy example of what I meant on the last paragraph:

```tsx
import { RefObject, useEffect, useState, ReactElement, useRef } from "react";

import type { NextPage } from "next";
import dynamic from "next/dynamic";
import Link from "next/link";

const LazyButton = dynamic(() => import("../components/Button"));

interface Args extends IntersectionObserverInit {
  freezeOnceVisible?: boolean;
}

function useIntersectionObserver(
  elementRef: RefObject<Element>,
  {
    threshold = 0,
    root = null,
    rootMargin = "0%",
    freezeOnceVisible = false,
  }: Args
): IntersectionObserverEntry | undefined {
  const [entry, setEntry] = useState<IntersectionObserverEntry>();

  const frozen = entry?.isIntersecting && freezeOnceVisible;

  const updateEntry = ([entry]: IntersectionObserverEntry[]): void => {
    setEntry(entry);
  };

  const stableThreshold = Array.isArray(threshold)
    ? threshold.join(";")
    : threshold;

  useEffect(() => {
    const node = elementRef?.current;
    const hasIOSupport = !!window.IntersectionObserver;

    if (!hasIOSupport || frozen || !node) return;

    const inputThreshold =
      typeof stableThreshold === "string"
        ? stableThreshold.split(";").map(Number)
        : stableThreshold;

    const observerParams = { threshold: inputThreshold, root, rootMargin };
    const observer = new IntersectionObserver(updateEntry, observerParams);

    observer.observe(node);

    return () => observer.disconnect();
  }, [elementRef, stableThreshold, root, rootMargin, frozen]);

  return entry;
}

const RenderWithWindowIntersection = ({
  children,
}: {
  children: ({ visible }: { visible: boolean }) => ReactElement;
}) => {
  const ref = useRef<HTMLDivElement | null>(null);
  const entry = useIntersectionObserver(ref, {});
  const visible = Boolean(entry?.isIntersecting);

  return (
    <div ref={ref}>
      <>{children({ visible })}</>
    </div>
  );
};

const Home: NextPage = () => {
  return (
    <div>
      <h1 id="home">Home</h1>

      <Link href="/blog">blog</Link>

      <div style={{ height: "200vh" }}></div>

      <RenderWithWindowIntersection>
        {({ visible }) => {
          return <>{visible ? <LazyButton /> : null}</>;
        }}
      </RenderWithWindowIntersection>
    </div>
  );
};

export default Home;
```

