I was trying to secure a specific file like `_next/static/chunks/pages/my-private-page-somehash.js`

I solved it by creating an `api/static` endpoint, and adding a redirect to `.next.config.mjs`

```ts
// src/pages/api/static.ts

import fs from "fs";
import path from "path";
import { type NextApiRequest, type NextApiResponse } from "next";
import { getToken } from "next-auth/jwt";

const handler = async (req: NextApiRequest, res: NextApiResponse) => {
  const { path: thePath } = req.query;

  const token = await getToken({ req, secret: process.env.SECRET });

  if ((thePath as string).startsWith("my-private-page-") && !token) {
    res.status(401).json({ error: "Unauthorized" });
    return;
  }

  const file = fs.readFileSync(
    path.join(process.cwd(), ".next/static/chunks/pages", thePath as string)
  );

  res.status(200).send(file);
};

export default handler;

export const config = {
  api: {
    responseLimit: false,
  },
};
```


```ts
// next.config.mjs

// ...
const config = {
  // ...
  redirects: async () => {
      return [
        {
          source: "/_next/static/chunks/pages/:path*",
          destination: "/api/static?path=:path*",
          permanent: false,
        },
      ];
    }
  // ...
}
// ...
```

With this change, only logged in users are able to fetch `my-private-page-somehash.js`

Not the best solution but easy to implement and gets the job done.

