I was still having some issues with the above so I created a plugin that's easy to use with next-compose-plugins:
```js
const withSVGR = (nextConfig) => {
  nextConfig.webpack = (config, options) => {
    config.module.rules.map((rule) => {
      if (rule.test !== undefined && rule.test.source.includes('|svg|')) {
        rule.test = new RegExp(rule.test.source.replace('|svg|', '|'));
      }
    });
    config.module.rules.push({
      test: /\.svg$/i,
      issuer: /\.[jt]sx?$/,
      use: ['@svgr/webpack'],
    });
    return config;
  };
  return nextConfig;
};
```

