I've been able to get hot refresh on changes to certain `node_module` with this `next.config.js`. 

By default all files in `node_modules` webpack assumes will not be modified. We need to update the `managedPaths` property of the webpack `snapshot` config to exclude whatever modules you want webpack to watch for changes in.
https://webpack.js.org/configuration/other-options/#managedpaths

```
let config = {
  reactStrictMode: true,
  swcMinify: true,
  eslint: {
    dirs: ['pages', 'src', '__tests__', 'cypress'],
  },
  webpack: (config) => {
    config.snapshot = {
      ...(config.snapshot ?? {}),
      // Add all node_modules but @next module to managedPaths
      // Allows for hot refresh of changes to @next module
      managedPaths: [/^(.+?[\\/]node_modules[\\/])(?!@next)/],
    };
    return config;
  },
};

if (process.env.ANALYZE === 'true') {
  const withBundleAnalyzer = require('@next/bundle-analyzer')({
    enabled: true,
  });
  config = withBundleAnalyzer(config);
}

module.exports = config;
```

