Just to summarise and hopefully save someone some time :
- Next uses its Edge runtime for middleware
- pino-pretty doesn't work on this runtime
- As of [15.2](https://nextjs.org/blog/next-15-2#nodejs-middleware-experimental) there is experimental support for Node middleware, but this doesn't seem to resolve this issue. 
- You can use the same approach to logging in the browser to format messages logged from the edge runtime
- You can detect whether the runtime is edge using `process?.env?.NEXT_RUNTIME === `edge``
- You can use this to toggle how you are logging (like you might already be toggling between server and client-side logging)
- Here is an example that is working:

```TypeScript
const serverNodeRuntimeConfig = {
  transport: {
    target: `pino-pretty`,
    options: {
      colorize: true,
      messageFormat: `[{group}] {msg}`,
      hideObject: true,
      ignore: `pid,hostname`,
    },
  },
}

const defaultConfig = {
  browser: {
    write: (logObj: unknown) => {
      const { level, msg, group, time, icon } = logObj as Record<string, string>

      const levelUppercased = level.toUpperCase()
      const timeFormatted = format(new Date(time), `HH:mm:ss.sss`)
      const levelColor = getLevelColor(levelUppercased)

      // Output the formatted message using console.log
      console.log(
        `[${timeFormatted}] ${levelColor}${levelUppercased} ${COLOR.CYAN}[${icon} ${group}] ${msg} ${COLOR.WHITE}`
      )
    },
    formatters: {
      level: (label: string) => {
        return {
          level: label,
        }
      },
    },
  },
}

const baseLogger: Logger = pino({
  ...baseConfig,
  ...(ENVIRONMENT.IS_RUNTIME_NODE ? serverNodeRuntimeConfig : defaultConfig),
  // Disable logging on the client unless in development
  enabled: ENVIRONMENT.IS_SERVER || ENVIRONMENT.IS_DEVELOPMENT,
})
```

