Because nextjs polyfills the Response in node side with node-fetch, so I always use this function to extract all headers from Web Response.

```typescript
export function extractHeaderKeysFromWebResponseToServerResponse(
  response: Response,
  res: ServerResponse,
  ...headerKeys: string[]
) {
  const keys = headerKeys.length ? headerKeys : [...response.headers.keys()]
  if ('getAll' in response.headers) {
    // get real all headers from node fetch headers
    keys.forEach(key => {
      const values = (response.headers as any).getAll(key) as string[]
      const cb = key.match(/^(x-|content-|via|cache-)/i) ? setHeader : appendHeader
      values.forEach(value => value && cb(res, key, value))
    })
  } else {
    keys.forEach(key => {
      const value = response.headers.get(key)
      const cb = key.match(/^(x-|content-|via|cache-)/i) ? setHeader : appendHeader
      value && cb(res, key, value)
    })
  }
}
```

Then you can extract set-cookie like this
```typescript
