I'd consider this a bug in the `externalDir` implementation. I worked around this by mapping the imports in the webpack config to an absolute path:

```js
// next.config.js

module.exports = {
  experimental: {
    externalDir: true,
  },
  webpack: (
    config,
    { buildId, dev, isServer, defaultLoaders, nextRuntime, webpack }
  ) => {
    // Important: return the modified config
    return {
      ...config,
      resolve: {
        ...config.resolve,
        fallback: {
          "react/jsx-dev-runtime": path.resolve(
            __dirname,
            "node_modules/react/jsx-dev-runtime.js"
          ),
          react: path.resolve(__dirname, "node_modules/react"),
        },
      },
    };
  },
};

