      if (!Hls) {
        console.error(
          "Browser does not support HLS - please use another browser"
        );
        return;
      }

      if (!playerRef.current) {
        console.error("Video element not available, cannot load video");
        return;
      }

      if (hls.current !== null) {
        hls.current?.destroy();
      }

      const newHls = new Hls({
