Hi, I'm not sure we should completely throw away the default `transformIgnorePatterns` if one is provided since this could accidentally cause `.next` and all of `node_modules` to be transformed. Instead you can augment the built config e.g.

```js
const nextJest = require('next/jest')

const createJestConfig = nextJest({
  // Provide the path to your Next.js app to load next.config.js and .env files in your test environment
  dir: './',
})

// Add any custom config to be passed to Jest
const customJestConfig = {
  // Add more setup options before each test is run
  // setupFilesAfterEnv: ['<rootDir>/jest.setup.js'],
  // if using TypeScript with a baseUrl set to the root directory then you need the below for alias' to work
  moduleDirectories: ['node_modules', '<rootDir>/'],
  testEnvironment: 'jest-environment-jsdom',
}

module.exports = async (...args) => {
  const fn = createJestConfig(customJestConfig)
  const res = await fn(...args)
  
  res.transformIgnorePatterns = res.transformIgnorePatterns.map(pattern => {
    if (pattern === '/node_modules/') {
      return '/node_modules(?!/excluded-module)/'
    }
    return pattern
  })
  
  return res
}
```

