I've just created a package, [next-plugin-websocket](https://github.com/sam3d/next-plugin-websocket), that adds support for WebSocket handlers in Next.js API routes with no extra configuration:

```ts

import { appRouter } from "@/server/routers/_app";
import { NextApiHandler } from "next";
import { NextWebSocketHandler } from "next-plugin-websocket";

export const socket: NextWebSocketHandler = (client, req) => {
  client.on("message", (msg) => {
    client.send(msg);
  });
};

const handler: NextApiHandler = (req, res) => {
  res.status(426).end();
};

export default handler;
```

