const components = {
  h1: (props) => (
    <h1 {...props} className={`text-lg ${props.className || ""}`} />
  ),
  article: (props) => (
    <article
      {...props}
      className={`prose lg:prose-xl ${props.className || ""}`}
    />
  )
};
```
