I've just spent a very frustrating 8 hours wrestling with wasm problems in Webpack 5 + Next.JS, same error described above: a wasm file simply missing from the output folder where it should've been. I had previously had the issue with the wasm file being placed in the wrong folder (with Webpack 4), and I did the workaround using "webassemblyModuleFilename" for that and it worked, but for some reason today it has decided to randomly stop working. Something to do with us being forced onto Webpack 5 I think.. but I didn't upgrade any packages so I'm a little confused what triggered it.

Anyway, I have solved it, the key for me was to use Webpack 5's new Asset Modules to serve up the wasm files instead. 
https://webpack.js.org/guides/asset-modules/
Here's my config in case it's helpful to anyone: 

```
const nextConfig = {
  reactStrictMode: false,
  swcMinify: false,
  env: {
    SOCKET_PORT: process.env.SOCKET_PORT,
  },
  rewrites: () => {
    return [
      // we need to define a no-op rewrite to trigger checking
      // all pages/static files before we attempt proxying
      {
        source: '/:path*',
        destination: '/:path*',
      },
    ];
  },
  webpack: function (config, options) {
    config.experiments = { asyncWebAssembly: true, syncWebAssembly: true, layers: true, topLevelAwait: true };
    config.resolve.fallback = { fs: false, path: false, dns: false, net: false, tls: false };
   
    patchWasmModuleImport(config, options.isServer);
    config.stats = {};
    config.stats.warningsFilter = [/emurgo/i];
    config.plugins.push(
      new FilterWarningsPlugin({
        exclude: /emurgo/,
      }),
    );

    return config;
  },
};
function patchWasmModuleImport(config, isServer) {
  config.experiments = Object.assign(config.experiments || {}, {
    asyncWebAssembly: true,
  });
  config.module.defaultRules = [
    {
      type: 'javascript/auto',
      resolve: {},
    },
    {
      test: /\.json$/i,
      type: 'json',
    },
  ];
  config.optimization.moduleIds = 'named';

  config.module.rules.push({
    test: /\.wasm$/,
    type: 'asset/resource',
  });

  // TODO: improve this function -> track https://github.com/vercel/next.js/issues/25852
  if (isServer) {
    config.output.webassemblyModuleFilename = './../static/wasm/[modulehash].wasm';
  } else {
    config.output.webassemblyModuleFilename = 'static/wasm/[modulehash].wasm';
  }
```

