  export type GetStaticProps<
    P extends { [key: string]: any } = { [key: string]: any },
    Q extends ParsedUrlQuery = ParsedUrlQuery,
    D extends PreviewData = PreviewData
  > = (context: {
    params?: Q;
    preview?: boolean;
    previewData?: D;
    locale?: "pt" | "en";
    locales?: string[];
    defaultLocale?: string;
  }) => Promise<GetStaticPropsResult<P>> | GetStaticPropsResult<P>;
}

```

Note that I don't advocate for this since your custom type will be out of sync with the official ones.
If there is a change in the Next.js typings, you won't notice it.

Moreover, redeclaring a module like this will override the other type definitions.
If you **really** want to do it, I suggest creating a custom type and explicitly using it like 
`export const getStaticProps: MyCustomType = async () => `

