import { wrapGetServerSideProps } from "my-lib"

function Page() {
  return <div> … </div>
}

export const getServerSideProps = wrapGetServerSideProps(async (ctx) => {
  // stuff happens
})
```

The `my-lib` module could live anywhere on the filesystem. The `__dirname` or `__filename` or `import.meta.url` has no relation to the page.

