```ts
export const getServerSideProps = (ctx) => {
  const __filename = 'something'
  return wrapGetServerSideProps(async (ctx) => {
    // stuff happens
  })(ctx, __filename); // or maybe enhance `ctx` to extend the `GetServerSidePropsContext` type
};

// or

const __filename = "calculate-file-name"; 
