I'd recommend also thinking of using _middleware, if possible, to check the pathname of the request, and rewrite it to a simple file, which should remain itself unreachable (this last bit you can also control with _middleware). Assuming, you'd scope everything to a page called `client-data.tsx`

```ts
import { NextRequest, NextResponse } from "next/server";

export const middleware = async (req: NextRequest) => {
  const { pathname } = req.nextUrl;

  // prevent direct access to `/client-data`
  if (pathname.startsWith("/client-data")) {
    return new Response(null, { status: 404, statusText: "Not Found" });
  }

  const client = createClient(req);
  const isValid = await client.isValidPath(pathname)
 
  if (!isValid) {
    return new Response(null, { status: 404, statusText: "Not Found" });
  }

  if (
    pathname.startsWith("/api") || //  exclude all API routes
    pathname.startsWith("/static") || // exclude static files
    pathname.includes(".") // exclude all files in the public folder
  ) {
    return NextResponse.next();
  }

  req.nextUrl.searchParams.set("pathname", pathname);

  const url = req.nextUrl.clone();
  url.pathname = "/client-data";

  return NextResponse.rewrite(url); // should include a query param called pathname
 // which you can use in `/client-data` to render as you require. 
};
```

