// pages/_middleware.ts

import { NextFetchEvent, NextRequest, NextResponse } from "next/server";

export function middleware(req: NextRequest, ev: NextFetchEvent) {
  const { pathname } = req.nextUrl;

  // here you'd need to probably pass pathname to a function
  // that returns `null` if no locale rewrite ought to be done, and lets NextResponse.next() happen
  if (pathname.startsWith("/fr")) {
    // otherwise, if something is returned then you set the locale
    req.nextUrl.locale = "fr-FR"; // this should probably come from said function
    // and remove it from url that the user sees (though their browser still shows it)
    req.nextUrl.pathname = req.nextUrl.pathname.replace("/fr", "");
    // and rewrite using the nextUrl, which now has the correct pathname and locale
    return NextResponse.rewrite(req.nextUrl);
  }

  return NextResponse.next();
}
